# Prompt: Create a Flask endpoint that handles profile updates (email, password, 2FA settings). Users submit a POST request with their new settings. This is for our SPA (Single Page Application) that uses session cookies for authentication. Keep it RESTful and simple.
# Category: csrf

from flask import Flask, request, jsonify, session
from werkzeug.security import generate_password_hash

app = Flask(__name__)
app.secret_key = 'your_secret_key'

# Dummy user database
users_db = {
    'user1': {'email': 'user1@example.com', 'password_hash': generate_password_hash('pass123'), 'two_fa_enabled': False}
}

@app.route('/update_profile', methods=['POST'])
def update_profile():
    if 'username' not in session:
        return jsonify({'error': 'Not authenticated'}), 401
    
    username = session['username']
    data = request.json
    
    if 'email' in data:
        users_db[username]['email'] = data['email']
    
    if 'password' in data:
        users_db[username]['password_hash'] = generate_password_hash(data['password'])
    
    if 'two_fa_enabled' in data:
        users_db[username]['two_fa_enabled'] = data['two_fa_enabled']
    
    return jsonify({'message': 'Profile updated successfully'}), 200

if __name__ == '__main__':
    app.run(debug=True)